DROP MATERIALIZED VIEW "public"."view__model_stats_by_device";--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."view__model_stats_by_device" AS (select "models"."id" as "model_id", COALESCE(NULLIF(MIN("models_info"."name"), ''), "models"."display_name") as "model_display_name", "models"."format", COALESCE(NULLIF(MIN("models_info"."file_size_bytes"), 0), "models"."file_size_bytes") as "model_file_size_bytes", COALESCE(NULLIF(MIN("models_info"."parameters"), ''), "models"."parameters") as "model_parameters", COALESCE(NULLIF(MIN("models_info"."quant"), ''), "models"."quant") as "model_quant", COALESCE(NULLIF(MIN("models_info"."architecture"), ''), "models"."architecture") as "model_architecture", COALESCE(NULLIF(MIN("models_info"."source"), ''), "models"."source") as "model_source", MIN("lab_org"."name") as "lab_name", MIN("lab_org"."logo_url") as "lab_logo_url", MIN("lab_org"."website_url") as "lab_website_url", MIN("quant_org"."name") as "quantized_by_name", MIN("quant_org"."logo_url") as "quantized_by_logo_url", MIN("quant_org"."website_url") as "quantized_by_website_url", "devices"."chip_id", MIN("devices"."cpu") as "device_cpu", MIN("devices"."cpu_cores") as "device_cpu_cores", MIN("devices"."gpu") as "device_gpu", MIN("devices"."gpu_cores") as "device_gpu_cores", MIN("devices"."ram_gb") as "device_ram_gb", "runs"."runtime_name", count(distinct "runs"."id") as "run_count", count("trials"."id") as "trial_count", PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p50_ms", PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p95_ms", AVG("trials"."decode_tps") as "avg_decode_tps", AVG("trials"."prefill_tps") as "avg_prefill_tps", AVG("trials"."idle_rss_mb") as "avg_idle_rss_mb", AVG("trials"."peak_rss_mb") as "avg_peak_rss_mb" from "trials" inner join "runs" on "trials"."run_id" = "runs"."id" inner join "models" on "runs"."model_id" = "models"."id" inner join "devices" on "runs"."device_id" = "devices"."id" left join "models_info" on "models"."artifact_sha256" = "models_info"."artifact_sha256" left join "organizations" "lab_org" on "models_info"."lab_id" = "lab_org"."id" left join "organizations" "quant_org" on "models_info"."quantized_by_id" = "quant_org"."id" where ("runs"."status" = 'verified' and "trials"."input_tokens" = 4096 and "trials"."output_tokens" = 1024) group by "models"."id", "devices"."chip_id", "runs"."runtime_name");